powershell # Windows PowerShell Script for Environment Setup Write-Host "========================================" -ForegroundColor Cyan Write-Host " Starting AI Environment Setup (Windows)" -ForegroundColor Cyan Write-Host "========================================" -ForegroundColor Cyan if (Test-Path ".env.example") { Copy-Item ".env.example" -Destination ".env" Write-Host "[SUCCESS] Configuration file (.env) generated." -ForegroundColor Green } else { Write-Host "[ERROR] Template file not found!" -ForegroundColor Red }